import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { UserDTO } from '../../../core/models/user.model';

@Component({
  selector: 'app-header',
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss']
})
export class HeaderComponent implements OnInit {
  currentUser: UserDTO | null = null;
  isMobileMenuOpen = false;
  hoverState = false;

  constructor(
    private authService: AuthService,
    public router: Router
  ) {}

  ngOnInit(): void {
    console.log('Header - Initializing');
    this.authService.currentUser$.subscribe(user => {
      this.currentUser = user;
      console.log('Header - User updated:', user);
      console.log('Header - Current user after update:', this.currentUser);
    });

    // Debug: check if there's a token
    console.log('Header - Has token:', this.authService.hasToken());
    console.log('Header - Token:', this.authService.getToken());
  }

  toggleMobileMenu(): void {
    this.isMobileMenuOpen = !this.isMobileMenuOpen;
  }

  logout(): void {
    this.authService.logout().subscribe({
      complete: () => {
        this.authService.clearAuth();
        this.router.navigate(['/auth/login']);
        this.isMobileMenuOpen = false;
      }
    });
  }

  navigateTo(route: string): void {
    this.router.navigate([route]);
    this.isMobileMenuOpen = false;
  }
}
